    'adv_qrm_q2': { type: 'mcq', questionText: { ar: 'يتم احتساب RPN بـ:', en: 'RPN is mathematically plotted via:' }, options: { ar: ['S + O + D', 'S × O × D', 'تخمين رقمي أعمى', 'سرعة الإنتاج'], en: ['S + O + D', 'S × O × D', 'Blind numerical guess', 'Production velocity'] }, correctAnswer: 1 },
    'adv_qrm_q3': { type: 'mcq', questionText: { ar: 'هل يمكننا خفض شدة تأثير جرثومة سامة على المريض (Severity) بتعديل الماكينات؟', en: 'Can we lower the poisonous biological severity of a germ on the patient by altering machines?' }, options: { ar: ['نعم بقوة', 'لا (عامل طبي ثابت)', 'ربما', 'نعم بعد إضافة حساس كاميرا'], en: ['Yes powerfully', 'No (Constant medical factor)', 'Possibly', 'Yes after adding camera sensor'] }, correctAnswer: 1 },
    'adv_qrm_q4': { type: 'mcq', questionText: { ar: 'أداة الشجرة FTA تنطلق من الأسفل للأعلى أم الأعلى للأسفل؟', en: 'FTA tool analyzes upwards (Bottom-Up) or downwards (Top-Down)?' }, options: { ar: ['أسفل لأعلى', 'عشوائي الدوران', 'من الحدث (أعلى) لأسبابه (لأسفل) Top-Down', 'رأسيا فقط للمستقبل'], en: ['Bottom-Up', 'Random rotating', 'Event (Top) to causes (Down) Top-down', 'Vertical pure future'] }, correctAnswer: 2 },
