    'adv_qrm_tf2': { type: 'tf', questionText: { ar: 'تحديث ICH Q9(R1) يشجع على التفكير الذاتي الشخصي الخالي من الأدلة.', en: 'ICH Q9(R1) update embraces personal subjective ideology devoid of proofs.' }, correctAnswer: false },
    'adv_gdp_q1': { type: 'mcq', questionText: { ar: 'ما هي النقطة الأكثر أهمية للتحقق من سلسلة التبريد الدوائية؟', en: 'What is the most critical point for validating the pharmaceutical cold chain?' }, options: { ar: ['لون الثلاجة الخارجي', 'المسح الحراري (Mapping) وتحديد نقاط السخونة والبرودة', 'حجم سيارة النقل', 'ماركة جهاز التبريد'], en: ['External fridge color', 'Temperature mapping to identify hot & cold spots', 'Transport car size', 'Cooler brand'] }, correctAnswer: 1 },
    'adv_gdp_q2': { type: 'mcq', questionText: { ar: 'كيف يمكن تجنب تجميد الأدوية (Cold shock) في الشواحن السلبية (Passive)؟', en: 'How to evade freezing (Cold Shock) within passive shippers?' }, options: { ar: ['عبر نزع الغلاف الخارجي', 'باستخدام فواصل كرتونية تمنع التلامس المباشر مع أكياس التبريد', 'برفع نسبة الماء فيها', 'بحقن السائل بالنيتروجين'], en: ['Removing outer wrappers', 'Imposing cardboard separators preventing direct contact with gel packs', 'Increasing water density', 'Injecting nitrogen'] }, correctAnswer: 1 },
    'adv_gdp_q3': { type: 'mcq', questionText: { ar: 'صيدلية أرادت إرجاع اللقاح و"ادعت" حفظها بالثلاجة لكن لا تمتلك سجلات الداتا لوجر؟', en: 'A pharmacy returns a vaccine claiming fridge storage but offers zero data logger plots?' }, options: { ar: ['نأخذه بحسن النية ونعيده للبيع', 'يُرفض ويعدم تماما حفاظا على سلامة المرضى', 'يتم غسيله بالكحول وبيعه', 'يُوزع مجاناً للفقراء'], en: ['We take it in good faith to resell', 'Instantly rejected and incinerated protecting patients', 'Washed in IPA and sold', 'Given freely to paupers'] }, correctAnswer: 1 },
    'adv_gdp_q4': { type: 'mcq', questionText: { ar: 'أين تتمركز البقعة شديدة البرودة (Cold Spot) أحياناً في الشاحنات المبردة Active؟', en: 'Where does the severe Cold Spot dynamically hover in an active reefer truck?' }, options: { ar: ['بجانب المحرك الخارجي', 'مباشرة أمام مصدات ضخ المكيف الهوائي البارد', 'وسط المنتصف', 'على العجلات'], en: ['Next to outer motor', 'Directly blasting immediately in front of AC fans', 'Dead center', 'On the wheels'] }, correctAnswer: 1 },
    'adv_gdp_tf1': { type: 'tf', questionText: { ar: 'مسجلات البيانات (Data Loggers) يجب معايرتها وتوثيقها بشكل دوري لضمان الدقة.', en: 'Data Loggers must be calibrated and documented periodically to ensure accuracy.' }, correctAnswer: true },
